func solve(m int64, n int64, waitCost [][]int64) int64 {
    rows := int(m)
    cols := int(n)

    // Create a DP table where dp[i][j][k] represents the minimal cost to reach (i,j)
    // at step k (0: odd step, 1: even step)
    dp := make([][][]int64, rows)
    for i := range dp {
        dp[i] = make([][]int64, cols)
        for j := range dp[i] {
            dp[i][j] = make([]int64, 2)
            dp[i][j][0] = 1 << 62 // Initialize to a large number
            dp[i][j][1] = 1 << 62
        }
    }

    // Starting point (0,0) at step 1 (odd step)
    dp[0][0][0] = (0 + 1) * (0 + 1)

    // Directions for moving (right and down)
    dirs := [][]int{{0, 1}, {1, 0}}

    for step := 1; ; step++ {
        updated := false

        // Create a new temporary DP table to store updates
        newDp := make([][][]int64, rows)
        for i := range newDp {
            newDp[i] = make([][]int64, cols)
            for j := range newDp[i] {
                newDp[i][j] = make([]int64, 2)
                newDp[i][j][0] = dp[i][j][0]
                newDp[i][j][1] = dp[i][j][1]
            }
        }

        for i := 0; i < rows; i++ {
            for j := 0; j < cols; j++ {
                if step%2 == 1 { // Odd step: move right or down
                    for _, dir := range dirs {
                        ni, nj := i+dir[0], j+dir[1]
                        if ni < rows && nj < cols {
                            cost := dp[i][j][0] + int64((ni+1)*(nj+1))
                            if cost < newDp[ni][nj][1] {
                                newDp[ni][nj][1] = cost
                                updated = true
                            }
                        }
                    }
                } else { // Even step: wait
                    cost := dp[i][j][1] + waitCost[i][j]
                    if cost < newDp[i][j][0] {
                        newDp[i][j][0] = cost
                        updated = true
                    }
                }
            }
        }

        // Update the DP table
        dp = newDp

        // Check if we reached the target with minimal cost
        if !updated {
            break
        }
    }

    // The answer is the minimal of both states at (rows-1, cols-1)
    return min(dp[rows-1][cols-1][0], dp[rows-1][cols-1][1])
}

func min(a, b int64) int64 {
    if a < b {
        return a
    }
    return b
}
