	// Directions: right (0,1), down (1,0)
	directions := [][]int64{{0, 1}, {1, 0}}

	// Create a priority queue
	pq := make(PriorityQueue, 0)
	heap.Init(&pq)

	// Push the starting cell (0,0) with time 1 and cost (1*1)
	heap.Push(&pq, Cell{0, 0, 1, (0+1)*(0+1)})

	// Create a cost matrix to keep track of minimum cost to reach each cell at each time
	costMatrix := make([][]int64, m)
	for i := range costMatrix {
		costMatrix[i] = make([]int64, n)
		for j := range costMatrix[i] {
			costMatrix[i][j] = -1 // Initialize with -1 (unvisited)
		}
	}

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(Cell)
		i, j, time, cost := current.i, current.j, current.time, current.cost

		// If we've reached the destination, return the cost
		if i == m-1 && j == n-1 {
			return cost
		}

		// If we've already found a better way to reach this cell at this time, skip
		if costMatrix[i][j] != -1 && costMatrix[i][j] <= cost {
			continue
		}
		costMatrix[i][j] = cost

