import "math"

func solve(m int64, n int64, waitCost [][]int64) int64 {
    M := int(m)
    N := int(n)

    // Create a DP table where dp[i][j][k] represents the minimal cost to reach (i,j)
    // at step k (0: odd step, 1: even step)
    dp := make([][][]int64, M)
    for i := range dp {
        dp[i] = make([][]int64, N)
        for j := range dp[i] {
            dp[i][j] = make([]int64, 2)
            dp[i][j][0] = math.MaxInt64
            dp[i][j][1] = math.MaxInt64
        }
    }

    // Initial position (0,0) at step 1 (odd step)
    dp[0][0][0] = (0 + 1) * (0 + 1)

    for step := 1; step <= 2*M*N; step++ {
        for i := 0; i < M; i++ {
            for j := 0; j < N; j++ {
                currentParity := step % 2
                if currentParity == 1 { // Odd step: can move from previous even step (wait)
                    // Check if we can come from up or left
                    minPrev := int64(math.MaxInt64)
                    if i > 0 {
                        if dp[i-1][j][0] < minPrev {
                            minPrev = dp[i-1][j][0]
                        }
                    }
                    if j > 0 {
                        if dp[i][j-1][0] < minPrev {
                            minPrev = dp[i][j-1][0]
                        }
                    }
                    if minPrev != math.MaxInt64 {
                        cost := minPrev + (int64(i)+1)*(int64(j)+1)
                        if cost < dp[i][j][1] {
                            dp[i][j][1] = cost
                        }
                    }
                } else { // Even step: can wait from previous odd step (move)
                    if dp[i][j][1] != math.MaxInt64 {
                        cost := dp[i][j][1] + waitCost[i][j]
                        if cost < dp[i][j][0] {
                            dp[i][j][0] = cost
                        }
                    }
                }
            }
        }
    }

    // The result is the minimal of the two possible states at (M-1, N-1)
    result := dp[M-1][N-1][0]
    if dp[M-1][N-1][1] < result {
        result = dp[M-1][N-1][1]
    }
    return result
}
