func solve(m int64, n int64, waitCost [][]int64) int64 {
    rows := int(m)
    cols := int(n)

    // Create a DP table where dp[i][j][k] represents the minimal cost to reach (i,j)
    // at step k (0 for odd, 1 for even)
    dp := make([][][]int64, rows)
    for i := range dp {
        dp[i] = make([][]int64, cols)
        for j := range dp[i] {
            dp[i][j] = make([]int64, 2)
            dp[i][j][0] = 1 << 31 - 1 // Initialize to a large number
            dp[i][j][1] = 1 << 31 - 1
        }
    }

    // Starting point (0,0) at step 1 (odd step)
    dp[0][0][0] = (0 + 1) * (0 + 1)

    // Directions: right (0,1) and down (1,0)
    dirs := [][]int{{0, 1}, {1, 0}}

    for step := 1; ; step++ {
        updated := false

        for i := 0; i < rows; i++ {
            for j := 0; j < cols; j++ {
                for k := 0; k < 2; k++ {
                    if dp[i][j][k] == 1<<31-1 {
                        continue
                    }

                    currentCost := dp[i][j][k]

                    if step%2 == 1 { // Odd step: move
                        if k == 0 { // Previous was odd step (can move now)
                            for _, dir := range dirs {
                                ni, nj := i+dir[0], j+dir[1]
                                if ni < rows && nj < cols {
                                    newCost := currentCost + (int64(ni)+1)*(int64(nj)+1)
                                    if newCost < dp[ni][nj][1] {
                                        dp[ni][nj][1] = newCost
                                        updated = true
                                    }
                                }
                            }
                        }
                    } else { // Even step: wait
                        if k == 1 { // Previous was even step (can wait now)
                            newCost := currentCost + waitCost[i][j]
                            if newCost < dp[i][j][0] {
                                dp[i][j][0] = newCost
                                updated = true
                            }
                        }
                    }
                }
            }
        }

        if !updated {
            break
        }
    }

    // The answer is the minimal of the two states at (rows-1, cols-1)
    if dp[rows-1][cols-1][0] < dp[rows-1][cols-1][1] {
        return dp[rows-1][cols-1][0]
    }
    return dp[rows-1][cols-1][1]
