    rows := int(m)
    cols := int(n)

    // Create a DP table where dp[i][j][k] represents the minimal cost to reach (i,j)
    // k is 0 for odd step (move), 1 for even step (wait)
    dp := make([][][]int64, rows)
    for i := range dp {
        dp[i] = make([][]int64, cols)
        for j := range dp[i] {
            dp[i][j] = make([]int64, 2)
            dp[i][j][0] = 1 << 62 // Initialize to a large number
            dp[i][j][1] = 1 << 62
        }
    }

    // Starting point (0,0) at step 1 (odd)
    dp[0][0][0] = (0 + 1) * (0 + 1)

    for step := 1; step <= 2*rows*cols; step++ {
        isOdd := step % 2 == 1
        currentK := 0
        if !isOdd {
            currentK = 1
        }

        // Create a temporary DP to store updates for this step
        tempDP := make([][][]int64, rows)
        for i := range tempDP {
            tempDP[i] = make([][]int64, cols)
            for j := range tempDP[i] {
                tempDP[i][j] = make([]int64, 2)
                tempDP[i][j][0] = dp[i][j][0]
                tempDP[i][j][1] = dp[i][j][1]
            }
        }

        for i := 0; i < rows; i++ {
            for j := 0; j < cols; j++ {
                if isOdd {
                    // Move step: can come from up or left (previous step was even, waited)
                    minCost := int64(1 << 62)
                    if i > 0 {
                        cost := dp[i-1][j][1] + (int64(i)+1)*(int64(j)+1)
                        if cost < minCost {
                            minCost = cost
                        }
