                    if j > 0 {
                        cost := dp[i][j-1][1] + (int64(i)+1)*(int64(j)+1)
                        if cost < minCost {
                            minCost = cost
                        }
                    }
                    if minCost != 1<<62 && minCost < tempDP[i][j][0] {
                        tempDP[i][j][0] = minCost
                    }
                } else {
                    // Wait step: must have come from previous step (odd, moved)
                    cost := dp[i][j][0] + waitCost[i][j]
                    if cost < tempDP[i][j][1] {
                        tempDP[i][j][1] = cost
                    }
                }
