        dp[i] = make([][]int64, cols)
        for j := range dp[i] {
            dp[i][j] = make([]int64, 2)
            dp[i][j][0] = 1 << 60 // Initialize to a large number
            dp[i][j][1] = 1 << 60
        }
    }

    // Starting point (0,0) at step 1 (odd step)
    dp[0][0][0] = (0 + 1) * (0 + 1)

    for step := 1; step <= 2*rows*cols; step++ {
        currentParity := (step - 1) % 2 // 0 for odd steps (1,3,...), 1 for even steps (2,4,...)
        nextParity := step % 2

        // Create a new temporary DP table to avoid overwriting during processing
        newDp := make([][][]int64, rows)
        for i := range newDp {
            newDp[i] = make([][]int64, cols)
            for j := range newDp[i] {
                newDp[i][j] = make([]int64, 2)
                newDp[i][j][0] = dp[i][j][0]
                newDp[i][j][1] = dp[i][j][1]
            }
