        for i := 0; i < rows; i++ {
            for j := 0; j < cols; j++ {
                if currentParity == 0 { // Odd step: move right or down
                    // Right move
                    if j+1 < cols {
                        cost := dp[i][j][currentParity] + (int64(i)+1)*(int64(j+1)+1)
                        if cost < newDp[i][j+1][nextParity] {
                            newDp[i][j+1][nextParity] = cost
                        }
