                        }
                    }
                } else { // Even step: wait
                    cost := dp[i][j][currentParity] + waitCost[i][j]
                    if cost < newDp[i][j][nextParity] {
                        newDp[i][j][nextParity] = cost
                    }
                }
            }
        }

        // Update the DP table
        dp = newDp
    }

    // The answer is the minimal cost to reach (rows-1, cols-1) at any step
    result := dp[rows-1][cols-1][0]
    if dp[rows-1][cols-1][1] < result {
        result = dp[rows-1][cols-1][1]
    }

    return result
}
