import (
	"container/heap"
)

type Cell struct {
	i, j  int64
	time  int64
	cost  int64
}

type PriorityQueue []Cell

func (pq PriorityQueue) Len() int { return len(pq) }
func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}
func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}
func (pq *PriorityQueue) Push(x interface{}) {
	*pq = append(*pq, x.(Cell))
}
func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[:n-1]
	return item
}

func solve(m int64, n int64, waitCost [][]int64) int64 {
	// Directions: right (0, 1), down (1, 0)
	directions := [][]int64{{0, 1}, {1, 0}}

	// Initialize priority queue
	pq := make(PriorityQueue, 0)
	heap.Init(&pq)

	// Push the starting cell (0, 0) with time 1 and cost (1*1)
	heap.Push(&pq, Cell{0, 0, 1, 1 * 1})

	// Create a cost matrix to keep track of minimum cost to reach each cell at each time
	costMatrix := make([][]map[int64]int64, m)
	for i := int64(0); i < m; i++ {
		costMatrix[i] = make([]map[int64]int64, n)
		for j := int64(0); j < n; j++ {
			costMatrix[i][j] = make(map[int64]int64)
		}
	}
	costMatrix[0][0][1] = 1 * 1

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(Cell)
		i, j, time, cost := current.i, current.j, current.time, current.cost

		if i == m-1 && j == n-1 {
			return cost
		}

		if cost > costMatrix[i][j][time] {
			continue
		}

		if time%2 == 1 {
			// Odd time: move right or down
			for _, dir := range directions {
				ni, nj := i+dir[0], j+dir[1]
				if ni < m && nj < n {
					newTime := time + 1
					newCost := cost + (ni+1)*(nj+1)
					if val, exists := costMatrix[ni][nj][newTime]; !exists || newCost < val {
						costMatrix[ni][nj][newTime] = newCost
						heap.Push(&pq, Cell{ni, nj, newTime, newCost})
					}
				}
			}
		} else {
			// Even time: wait
			newTime := time + 1
			newCost := cost + waitCost[i][j]
			if val, exists := costMatrix[i][j][newTime]; !exists || newCost < val {
				costMatrix[i][j][newTime] = newCost
				heap.Push(&pq, Cell{i, j, newTime, newCost})
			}
		}
	}

	return -1
}
